-- awesome-list-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Awesome List', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'A curated collection of the best resources', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the format: Name — one-line description. Be specific about what makes this resource worth including."},"content":{"tips":"Keep it brief. A short paragraph or a few bullets explaining why this resource is featured. Include a link."},"formatting":["Links: always include the primary URL","Bullet lists: key features, highlights, or reasons to use it","Bold: highlight the resource name at the start","Code blocks: install commands or quick-start snippets"],"avoid":["Long reviews (this is a directory, not a review site)","Resources without a clear reason for inclusion","Dead links or abandoned projects without noting it","Duplicating the keySummary in the content body"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":1,"max":3000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (awesome-list)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('bb188407-bc36-445f-84d4-90e31ae3f959', 'Submit Resource', 'submit-resource', 'Submit a resource for inclusion in the list', '[{"name":"name","type":"text","label":"Your Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"resource_url","type":"url","label":"Resource URL","required":true,"placeholder":"https://...","maxLength":500},{"name":"resource_title","type":"text","label":"Resource Title","required":true,"placeholder":"Name of the resource","maxLength":200},{"name":"why","type":"textarea","label":"Why should this be included?","required":true,"placeholder":"Describe the resource and why it deserves a spot on the list...","maxLength":2000}]', '{"success_message":"Thanks for the submission! We''ll review the resource and add it if it meets our curation standards.","require_honeypot":true}', 'active', '2026-03-27T01:22:41.638Z', '2026-03-27T01:22:41.638Z');
